const item = $input.first().json;
const dealId = item.body?.dealId || item.dealId;

if (!dealId) {
  throw new Error('No dealId found in webhook payload');
}

return [{
  json: {
    dealId: String(dealId)
  }
}];

const items = $input.all();

return items.flatMap(item => {
  const deal = item.json;
  const assoc = deal.associations || {};
  const lineItemIds = (assoc['line items']?.results || assoc['line_items']?.results || []).map(a => a.id);
  const companyId = (assoc['companies']?.results || [])[0]?.id;

  if (!companyId || lineItemIds.length === 0) return []; // skip silently

  return [{
    json: {
      dealId: deal.id,
      closedate: deal.properties.closedate,
      currency: deal.properties.deal_currency_code || 'EUR',
      pipeline: deal.properties.pipeline,
      companyId: companyId,
      lineItemIds: lineItemIds
    }
  }];
});

const items = $input.all();
const extractedItems = $('Extract Deal Data').all();

const currencySymbols = {
  'EUR': '\u20ac',
  'USD': '$',
  'GBP': '\u00a3',
  'CAD': 'CA$'
};
const pipelineLabels = {
  'default': 'New Business',
  '3585124587': 'Expansion'
};

return items.flatMap((item, index) => {
  const batchResponse = item.json;
  const lineItems = batchResponse.results || [];
  if (lineItems.length === 0) return [];

  const dealData = extractedItems[index].json;
  const currency = dealData.currency || 'EUR';
  const symbol = currencySymbols[currency] || currency + ' ';
  const pipelineLabel = pipelineLabels[dealData.pipeline] || dealData.pipeline;

  const closeDate = new Date(dealData.closedate);
  const day = String(closeDate.getDate()).padStart(2, '0');
  const month = String(closeDate.getMonth() + 1).padStart(2, '0');
  const year = closeDate.getFullYear();
  const formattedDate = day + '/' + month + '/' + year;

  const header = '[' + formattedDate + ' \u00b7 ' + pipelineLabel + ']';

  const lines = lineItems.map(li => {
    const name = li.properties.name || 'Unknown Product';
    const qty = li.properties.quantity || '1';
    const amount = parseFloat(li.properties.amount || '0');
    const amountStr = symbol + amount.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    return name + ' \u00d7 ' + qty + ' \u2014 ' + amountStr;
  });

  // Detect product flags from raw line item names (case-insensitive substring match)
  const hasSSO = lineItems.some(li => (li.properties.name || '').toLowerCase().includes('sso'));
  const hasLegalRadar = lineItems.some(li => (li.properties.name || '').toLowerCase().includes('legal radar'));
  const isNewBusiness = dealData.pipeline === 'default';

  return [{ json: { companyId: dealData.companyId, newLineItems: header + '\n' + lines.join('\n'), hasSSO, hasLegalRadar, isNewBusiness } }];
});

const items = $input.all();
const grouped = {};

for (const item of items) {
  const companyId = item.json.companyId;
  if (!grouped[companyId]) {
    grouped[companyId] = { lineItemsArr: [], hasSSO: false, hasLegalRadar: false, isNewBusiness: false };
  }
  grouped[companyId].lineItemsArr.push(item.json.newLineItems);
  grouped[companyId].hasSSO = grouped[companyId].hasSSO || item.json.hasSSO;
  grouped[companyId].hasLegalRadar = grouped[companyId].hasLegalRadar || item.json.hasLegalRadar;
  grouped[companyId].isNewBusiness = grouped[companyId].isNewBusiness || item.json.isNewBusiness;
}

return Object.entries(grouped).map(([companyId, data]) => ({
  json: {
    companyId: companyId,
    newLineItems: data.lineItemsArr.join('\n\n'),
    hasSSO: data.hasSSO,
    hasLegalRadar: data.hasLegalRadar,
    isNewBusiness: data.isNewBusiness
  }
}));

const items = $input.all();
const groupedItems = $('Group by Company').all();

const results = [];
for (let i = 0; i < items.length; i++) {
  const company = items[i].json;
  const formatData = groupedItems[i].json;

  const existingValue = company.properties?.productpurchased || '';
  const existingLines = existingValue.trim() ? existingValue.trim().split('\n') : [];
  const newLines = formatData.newLineItems.split('\n');

  // Preserve blank lines (used as group separators), deduplicate only content lines
  const linesToAdd = newLines.filter(line => line === '' || !existingLines.includes(line));

  let updatedValue;
  if (existingLines.length > 0 && linesToAdd.length > 0) {
    updatedValue = existingLines.join('\n') + '\n\n' + linesToAdd.join('\n');
  } else if (existingLines.length > 0) {
    updatedValue = existingLines.join('\n');
  } else {
    updatedValue = linesToAdd.join('\n');
  }

  results.push({
    json: {
      companyId: company.id,
      companyName: company.properties?.name || 'Unknown',
      updatedProductPurchased: updatedValue,
      hasSSO: formatData.hasSSO,
      hasLegalRadar: formatData.hasLegalRadar,
      isNewBusiness: formatData.isNewBusiness
    }
  });
}

return results;
